 #include<bits/stdc++.h>
using namespace std;
long long t,a,b,c,d,ans;
int main()
{
    cin>>t;
    while(t--)
    {
        cin>>a>>b>>c>>d;
    	while(c!=a||d!=b)
    	{
    		if(a==c&&b==d) break;
    		if(d-b>=c)
            {
            	long long t=(d-b)/c;
				ans+=t;
				d=d-t*c;
            }
    		else if(c-a>=d) 
            {
            	long long t=(c-a)/d;
				ans+=t;
				c=c-t*d;
            }
            else
			{
				ans=-1;
				break;
			}
    	}
    	cout<<ans<<"\n";
        ans=0;
    }

	return 0; 
}
